* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Roboto', 'Oxygen',
    'Ubuntu', 'Cantarell', 'Fira Sans', 'Droid Sans', 'Helvetica Neue',
    sans-serif;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  min-height: 100vh;
}

.container {
  width: 100%;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* Join Form Styles */
.join-form {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  padding: 2rem;
}

.join-form h1 {
  color: white;
  font-size: 3rem;
  margin-bottom: 1rem;
  text-align: center;
}

.join-form p {
  color: rgba(255, 255, 255, 0.9);
  font-size: 1.2rem;
  margin-bottom: 2rem;
  text-align: center;
}

.join-form form {
  background: white;
  padding: 2.5rem;
  border-radius: 12px;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
  width: 100%;
  max-width: 450px;
}

.form-group {
  margin-bottom: 1.5rem;
}

.form-group label {
  display: block;
  margin-bottom: 0.5rem;
  color: #333;
  font-weight: 600;
  font-size: 0.95rem;
}

.form-group input {
  width: 100%;
  padding: 0.875rem 1rem;
  border: 2px solid #e0e0e0;
  border-radius: 8px;
  font-size: 1rem;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.form-group input:focus {
  outline: none;
  border-color: #667eea;
  box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
}

.join-button {
  width: 100%;
  padding: 1rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  border-radius: 8px;
  font-size: 1.1rem;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.2s, box-shadow 0.2s;
}

.join-button:hover {
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(102, 126, 234, 0.4);
}

.join-button:active {
  transform: translateY(0);
}

/* Room Header Styles */
.room-header {
  background: white;
  padding: 1.5rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
  z-index: 10;
}

.room-header h1 {
  color: #333;
  font-size: 1.5rem;
}

.room-header p {
  color: #666;
  font-size: 1rem;
  margin: 0;
}

.leave-button {
  padding: 0.75rem 1.5rem;
  background: #ef4444;
  color: white;
  border: none;
  border-radius: 8px;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: background-color 0.2s;
}

.leave-button:hover {
  background: #dc2626;
}

/* LiveKit Components Override */
.lk-video-conference {
  flex: 1;
  background: #1a1a1a;
}

.lk-grid-layout {
  height: 100%;
}

.lk-participant-tile {
  background: #2a2a2a;
  border-radius: 8px;
  overflow: hidden;
}

.lk-control-bar {
  background: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(10px);
  border-radius: 12px;
}

.lk-button {
  border-radius: 8px;
}

.lk-button.lk-microphone,
.lk-button.lk-camera,
.lk-button.lk-screen-share {
  background: rgba(255, 255, 255, 0.1);
  border: 1px solid rgba(255, 255, 255, 0.2);
}

.lk-button.lk-microphone:hover,
.lk-button.lk-camera:hover,
.lk-button.lk-screen-share:hover {
  background: rgba(255, 255, 255, 0.2);
}

.lk-button.lk-end-call {
  background: #ef4444;
}

.lk-button.lk-end-call:hover {
  background: #dc2626;
}

.lk-chat {
  background: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(10px);
  border-radius: 12px;
}

.lk-chat-message {
  background: rgba(255, 255, 255, 0.1);
  border-radius: 8px;
}

/* Responsive Design */
@media (max-width: 768px) {
  .join-form h1 {
    font-size: 2rem;
  }

  .join-form form {
    padding: 2rem;
  }

  .room-header {
    flex-direction: column;
    gap: 1rem;
    text-align: center;
  }
}

